import React, { useState } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { useNavigate } from 'react-router-dom';
import { login } from '../store/slices/authSlice';
import toast from 'react-hot-toast';

const DEMO = [['principal','Principal'],['teacher1','Teacher'],['accountant','Accountant'],['parent1','Parent']];

export default function Login() {
  const [creds, setCreds] = useState({ username: 'admin', password: 'admin123' });
  const dispatch = useDispatch();
  const navigate = useNavigate();
  const { loading } = useSelector(s => s.auth);

  const handleSubmit = async (e) => {
    e.preventDefault();
    const res = await dispatch(login(creds));
    if (login.fulfilled.match(res)) { toast.success('Welcome back!'); navigate('/'); }
    else toast.error(res.payload || 'Login failed');
  };

  return (
    <div style={{ minHeight: '100vh', background: '#2D1B69', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
      <div style={{ background: '#fff', borderRadius: 20, padding: 36, width: 380, boxShadow: '0 20px 60px rgba(0,0,0,.25)' }}>
        <div style={{ textAlign: 'center', marginBottom: 24 }}>
          <div style={{ width: 52, height: 52, background: 'linear-gradient(135deg,#A78BFA,#F59E0B)', borderRadius: 14, display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 24, margin: '0 auto 12px' }}>🏫</div>
          <div style={{ fontSize: 20, fontWeight: 700 }}>EduManage</div>
          <div style={{ fontSize: 12, color: '#6B7280', marginTop: 3 }}>School Management System</div>
        </div>
        <form onSubmit={handleSubmit}>
          {['username','password'].map(f => (
            <div key={f} style={{ marginBottom: f === 'password' ? 18 : 12 }}>
              <label style={{ fontSize: 11, fontWeight: 700, color: '#4B5563', textTransform: 'uppercase', letterSpacing: '.06em', display: 'block', marginBottom: 5 }}>
                {f.charAt(0).toUpperCase()+f.slice(1)}
              </label>
              <input type={f === 'password' ? 'password' : 'text'} value={creds[f]}
                onChange={e => setCreds({...creds, [f]: e.target.value})}
                style={{ width: '100%', padding: '9px 12px', border: '1.5px solid #E5E7EB', borderRadius: 8, fontSize: 13, outline: 'none' }} />
            </div>
          ))}
          <button type="submit" disabled={loading}
            style={{ width: '100%', padding: 11, background: '#2D1B69', color: '#fff', border: 'none', borderRadius: 8, fontSize: 13, fontWeight: 600, cursor: loading ? 'wait' : 'pointer' }}>
            {loading ? 'Signing in…' : 'Sign In →'}
          </button>
        </form>
        <div style={{ marginTop: 16, border: '1.5px dashed #E5E7EB', borderRadius: 10, padding: 12 }}>
          <div style={{ fontSize: 10, fontWeight: 700, color: '#9CA3AF', textTransform: 'uppercase', letterSpacing: '.06em', marginBottom: 8 }}>Quick Demo</div>
          <div style={{ display: 'flex', gap: 6, flexWrap: 'wrap' }}>
            {DEMO.map(([u, l]) => (
              <button key={u} onClick={() => setCreds({ username: u, password: 'admin123' })}
                style={{ padding: '3px 10px', background: '#EDE9F8', border: '1px solid #C4B5FD', borderRadius: 20, fontSize: 11, fontWeight: 600, color: '#2D1B69', cursor: 'pointer' }}>
                {l}
              </button>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
}
